  "str_1011": "📦 Ibiri kugemurwa (3)",
  "str_1012": "<span class=\"dc-code\">RND-38291</span>\n        <span class=\"dc-status pending\">⏳ Pending Pickup</span>",
  "str_1013": "<strong>Sector:</strong> Gasabo — Kigali<br>\n        <strong>Time window:</strong> Morning (8am – 12pm)<br>\n        <strong>Kwita ku bafite ubumuga:</strong> None specified<br>\n        <strong>Ordered:</strong> 14 minutes ago",
