  "str_1015": "<span class=\"dc-code\">RND-52104</span>\n        <span class=\"dc-status transit\">🛵 In Transit</span>",
  "str_1016": "<strong>Sector:</strong> Kicukiro — Kigali<br>\n        <strong>Time window:</strong> Afternoon (12pm – 5pm)<br>\n        <strong>Kwita ku bafite ubumuga:</strong> Visually impaired — audio support needed<br>\n        <strong>Accepted:</strong> 2 hours ago",
  "str_1017": "<button class=\"dc-btn primary\" onclick=\"this.textContent='✅ Marked Delivered';this.disabled=true;this.parentElement.parentElement.querySelector('.dc-status').className='dc-status delivered';this.parentElement.parentElement.querySelector('.dc-status').textContent='✅ Delivered'\">Mark as Delivered</button>\n        <button class=\"dc-btn\" onclick=\"window.open('tel:114')\">📞 Call Support</button>",
