  "str_1020": "<button class=\"dc-btn primary\" onclick=\"this.textContent='✅ Accepted';this.disabled=true;this.parentElement.parentElement.querySelector('.dc-status').className='dc-status transit';this.parentElement.parentElement.querySelector('.dc-status').textContent='🛵 In Transit'\">Accept &amp; Start</button>\n        <button class=\"dc-btn\">View Details</button>",
