  "str_1023": "<strong>Sector:</strong> Gasabo — Kigali<br>\n        <strong>Delivered:</strong> Yesterday, 3:42 PM · Amanota: ⭐⭐⭐⭐⭐",
  "str_1024": "<span class=\"dc-code\">RND-39871</span>\n        <span class=\"dc-status delivered\">✅ Delivered</span>",
