  "str_1111": "Ingano y'inyandiko",
  "str_1112": "<button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize-2)\">A-</button><button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize+2)\">A+</button>",
  "str_1113": "Certificate Locked",
  "str_1114": "Complete all 3 learning quizzes in the Learn section to unlock your Certificate of Empowerment.",
  "str_1115": "<!-- Populated by JS -->",
  "str_1116": "📖 Go to Learn →",
  "str_1117": "🛡️ Rinda Initiative · iAccelerator 7",
