  "str_1483": "Ingano y'inyandiko",
  "str_1484": "<button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize-2)\">A-</button><button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize+2)\">A+</button>",
  "str_1485": "Gukurikirana igihe kimihango",
  "str_1486": "Igihe cy'Imihango &amp; Kwitaho",
  "str_1487": "Kurikirana imihango yawe, menya igihe izazira mu mezi 3 ari imbere, kandi ucunge ubuzima bwawe.",
  "str_1488": "<button class=\"m-tab active\" onclick=\"switchTab('tracker',this)\" role=\"tab\">📅 Iyandikishe</button>\n    <button class=\"m-tab\" onclick=\"switchTab('symptoms',this)\" role=\"tab\">🩺 Ibimenyetso &amp; Uko Wabyitwaramo</button>\n    <button class=\"m-tab\" onclick=\"switchTab('pads',this)\" role=\"tab\">♻️ Isuku no gutumiza ibikoresho by'isuku mugihe kimihango</button>",
  "str_1489": "🌸 Shyiraho Igikoresho cyawe",
  "str_1490": "Injiza amakuru y'imihango yawe kugira ngo umenye igihe izazira mu mezi 3. Amakuru yose aguma kuri telefone yawe — ni ibanga 100%.",
  "str_1491": "<label for=\"inp-last-period\">Igihe Imihango ya Nyuma Yatangiye</label>\n          <input type=\"date\" class=\"date-input\" id=\"inp-last-period\">",
  "str_1492": "Uburebure bw'Igihe (iminsi)",
  "str_1493": "<button class=\"stepper-btn\" onclick=\"step('cycle',-1)\" aria-label=\"Decrease\">−</button>\n            <span class=\"stepper-val\" id=\"cycle-val\">28</span>\n            <button class=\"stepper-btn\" onclick=\"step('cycle',1)\" aria-label=\"Increase\">+</button>",
  "str_1494": "Iminsi Imihango Imara (iminsi)",
  "str_1495": "<button class=\"stepper-btn\" onclick=\"step('dur',-1)\" aria-label=\"Decrease\">−</button>\n            <span class=\"stepper-val\" id=\"dur-val\">5</span>\n            <button class=\"stepper-btn\" onclick=\"step('dur',1)\" aria-label=\"Increase\">+</button>",
  "str_1496": "🔍 Kurikirana Nonaha",
  "str_1497": "Umunsi w'Imihango",
  "str_1498": "Iminsi Isigaye Imihango Ikaza",
  "str_1499": "Icyiciro Urimo",
  "str_1500": "<button class=\"btn-log\" id=\"btn-log-period\" onclick=\"logPeriodToday()\">🩸 Wandike ko Imihango Yaje Uyu Munsi</button>\n        <button class=\"btn-edit\" onclick=\"showSetup()\">⚙️ Hindura</button>",
  "str_1501": "📅 Incamake y'Amezi 3",
  "str_1502": "<!-- Populated by JS -->",
  "str_1503": "<button class=\"pg-btn\" onclick=\"shiftMonths(-3)\">← Amezi 3 Abanza</button>\n        <button class=\"pg-btn\" onclick=\"shiftMonths(3)\">Amezi 3 Akurikira →</button>",
  "str_1504": "<strong>Huza na kalendari yawe</strong><br>Kuramo ibyavumbuwe nka dosiye ya .ics kuri Google Calendar, iPhone, cyangwa Outlook.",
  "str_1505": "Kuramo",
  "str_1506": "📋 Amateka y'Imihango",
  "str_1507": "⚠️ Ibi ni ibigereranyo bishingiye ku makuru yawe. Imihango nyirizina ishobora gutandukana ho iminsi mike. Ibi ntibizimbura inama za muganga. Niba ubonye impinduka zikomeye, sura ikigo cy'ubuzima.",
  "str_1508": "Uracyiyumva ute uyu munsi?",
  "str_1509": "Kanda ku bimenyetso kugira ngo ubyandike maze ubone inama zihariye z'ubuzima.",
  "str_1510": "Ububabare",
  "str_1511": "Kuribwa n'umutwe",
  "str_1512": "umunaniro",
  "str_1513": "Guhinduka k'umutima",
  "str_1514": "kwarara",
  "str_1515": "Imihango myinshi",
  "str_1516": "Kuribwa n'umugongo",
  "str_1517": "Kubyimbirwa munda",
  "str_1518": "Ibishishi",
  "str_1519": "💡 Inama y'Ubuzima",
  "str_1520": "💾 Bika Ibimenyetso by'Uyu Munsi",
  "str_1521": "📦 Tumiza Cotex Zimeswa ku Buntu",
  "str_1522": "Shaka ikigo cy'urubyiruko kikuri hafi gitanga cotex zimeswa ku buntu, cyangwa uzitumize mu ibanga.",
  "str_1523": "Shaka aho Zitangirwa",
  "str_1524": "🧼 Inyoborabuzima n'Isuku",
  "str_1525": "<strong>Kuyinika mu mazi akonje:</strong> Buri gihe inika cotex yawe mu mazi akonje mbere. Amazi ashyushye atuma amaraso adashiramo.",
  "str_1526": "<strong>Kumesa n'isabune:</strong> Koresha isabune isanzwe y'umubiri cyangwa iy'imyenda. Fura umwenda witonze kugeza usukuye.",
  "str_1527": "<strong>Yimanike ahantu hari izuba ryinshi:</strong> Ibi ni ingenzi cyane. Izuba ryinshi ryica udukoko. Ntuyimanike ahantu hatose cyangwa hatagera izuba.",
  "str_1528": "<strong>Kuyibika neza:</strong> yibike mu gikapu gisukuye kandi cyumutse utegereje ukwezi gutaha.",
