  "str_1869": "<button class=\"lang-btn active\" data-lang=\"en\">EN</button>\n      <button class=\"lang-btn\" data-lang=\"kin\">KIN</button>",
  "str_1870": "♿ Kwita ku bafite ubumuga",
  "str_1871": "<span>Kugaragaza neza inyandiko</span><label class=\"toggle-switch\"><input type=\"checkbox\" onchange=\"toggleContrast(this.checked)\"><span class=\"toggle-slider\"></span></label>",
  "str_1872": "Ingano y'inyandiko",
  "str_1873": "<button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize-2)\">A-</button><button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize+2)\">A+</button>",
  "str_1874": "📦 Gutumizwa mu Ibanga",
  "orderPageTitle": "Gutumiza Igikoresho cyo Kwipima Virusi itera SIDA",
  "orderPageDesc": "Nta zina cyangwa indangamuntu bisabwa. Kizanwa n'umuforomo wafunzwe mu gipfunyika kitagaragaza.",
  "str_1875": "🔒 **Ibanga 100%:**&nbsp;Ntabwo tubika izina ryawe. Inomero y'akarere kawe gusa ni yo ifite akamaro.",
  "str_1876": "Intara / Akarere <span style=\"color:var(--red)\">*</span>",
  "str_1877": "— Hitamo akarere kawe —",
  "str_1878": "Gasabo — Kigali",
  "str_1879": "Kicukiro — Kigali",
  "str_1880": "Nyarugenge — Kigali",
