  "str_1893": "Karongi — Western",
  "str_1894": "Bikoreshwa mu kohereza inzego ya hafi. Ntago bishobora guhuzwa n'ibyangombwa byawe (identity).",
  "str_1895": "Nomero ya telefone <span class=\"optional\">(bidashyizweho — kugira ngo dushobore kukugezaho igikoresho)</span>",
  "str_1896": "🔒 Ibi bibikwa hano gusa mu gihe cyo kuzana igikoresho. Bivanywaho (deleted) nyuma yo kwemeza ko kageze.",
  "str_1897": "<label for=\"pickup\">Igihe wahitamo ko bakuzanira igikoresho <span class=\"optional\">(optional)</span></label>\n      <select id=\"pickup\">\n        <option value=\"\">Igihe icyo ari cyo cyose ni sawa</option>\n        <option>Mu gitondo (8am – 12pm)</option>\n        <option>Saa sita / Nyuma ya saa sita (12pm – 5pm)</option>\n        <option>Umugoroba (5pm – 8pm)</option>\n      </select>",
  "str_1898": "<label for=\"disability\">Kwita ku bafite ubumuga needs <span class=\"optional\">(optional)</span></label>\n      <select id=\"disability\">\n        <option value=\"\">Nta na kimwe</option>\n        <option>Abafite ubumuga bwo kureba — saba ubufasha bw'amajwi</option>\n        <option>Abatumva / Abafite ibibazo by'ubumenyi — saba inzego izi ururimi rw'amarenga</option>\n        <option>Abafite ubumuga bw'ingendo — saba ubufasha bwo kwinjira mu nzu</option>\n      </select>",
  "str_1899": "<input type=\"checkbox\" id=\"consent\" required=\"\" aria-required=\"true\">\n        <span>Nsobanukiwe ko iki gikoresho cyo kwipima ari icy'ubuzima bwanjye bwite kandi nemeye ko bampamagara gusa mu rwego rwo kumpereza igikoresho. <a href=\"knowledge.html\" style=\"color:var(--blue)\">Iga ku burenganzira bwawe →</a></span>",
  "str_1900": "📦 Saba Igikoresho Cyanjye — Ubuntu &amp; mu Ibanga",
  "str_1901": "Igikoresho Cyo Kwipima Cyasabwe!",
  "str_1902": "Inzego yawe yabwiwe. Igihe giteganijwe cyo kuzana: <strong style=\"color:var(--green)\">amasaa 24–48</strong>.",
  "str_1903": "INOMERO YO GUKURIKIRANA",
  "str_1904": "RND-00000",
  "str_1905": "Gusaba Koherejwe",
  "str_1906": "Gusaba kwawe mu ibanga kwakiriwe kandi kubitswe mu mutekano.",
  "str_1907": "Ubu nyine",
  "str_1908": "Inzego Yagiriwe",
  "str_1909": "Umuforomo wafunzwe hafi kawe yabwiwe kandi ategura igikoresho cyawe.",
  "str_1910": "~iminota 15–30",
  "str_1911": "Igikoresho Gipakijwe",
  "str_1912": "Igikoresho cyawe cyo kwipima gipakijwe mu gipfunyika gisanzwe, kitagaragaza izina n'ikimenyetso.",
  "str_1913": "~amasaa 2–4",
  "str_1914": "Ruganiro Gutura",
  "str_1915": "Inzego yawe iri mu nzira. Uzacika idirişa ntakwerekana — nta mapeti cyangwa ibimenyetso biri aho.",
  "str_1916": "~amasaa 12–24",
  "str_1917": "Kazanwe",
  "str_1918": "Igikoresho kazanwe. Inzego yawe izagaragaza uko gikoresha mu bwihisho. Nta nyandiko zisabwa.",
  "str_1919": "~amasaa 24–48",
  "str_1920": "Igihe Giteganijwe Cyo Kuzana",
  "str_1921": "Igikoresho cyawe kizazanwa mu gihe cy'amasaa <strong id=\"eta-time\">24–48</strong>. Igihe cy'ikigereranyo cyo kuzana mu karere kawe: <strong>amasaa 31</strong>.",
  "str_1922": "<button class=\"t-action-btn\" onclick=\"resetOrderForm()\">↺ Place Another Order</button>\n      <a href=\"knowledge.html\" class=\"t-action-btn primary\">📚 Prep: Read How to Use Kit →</a>",
  "str_1923": "Ufite ibibazo? Hamagara umurongo utishyurwa: <a href=\"tel:114\" style=\"color:var(--blue);font-weight:700\">114</a>\n        &nbsp;·&nbsp; Boneka amasaha 24/7 mu Kinyarwanda no mu Cyongereza",
