  "str_1934": "<button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize-2)\">A-</button><button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize+2)\">A+</button>",
  "str_1935": "❓ Ibanga · Hatanazina",
  "str_1936": "Ikizamini cyo Gupima Ibyago bya Virusi itera SIDA",
  "str_1937": "Ibibazo 5 by'ingenzi → urwego rwawe rw'ibyago + inzira zimwe zateganijwe. Ibanga 100%.",
  "str_1938": "Ikibazo cya 1 kuri 5",
  "str_1939": "Wigeze wipimishe Virusi itera SIDA ryari?",
  "str_1940": "Ibi bitugira uko dusobanukirwa n'aho ugeze mu kwipima.",
  "str_1941": "<button class=\"q-option\" onclick=\"selectOption(1,0,0)\"><span class=\"opt-icon\">✅</span>Mu mezi 6 ashize</button>\n        <button class=\"q-option\" onclick=\"selectOption(1,1,1)\"><span class=\"opt-icon\">📅</span>hashize amezi 6–12</button>\n        <button class=\"q-option\" onclick=\"selectOption(1,2,2)\"><span class=\"opt-icon\">⚠️</span>Hashize umwaka usaga</button>\n        <button class=\"q-option\" onclick=\"selectOption(1,3,3)\"><span class=\"opt-icon\">🚨</span>Ntabwo ndigera nipimisha</button>",
  "str_1942": "Ikibazo cya 2 kuri 5",
  "str_1943": "Urakoresha agakingirizo buri gihe mu gihe cy'imibonano?",
  "str_1944": "Kugikoresha neza buri gihe ni uburyo bw'ibanze bwo kwirinda.",
  "str_1945": "<button class=\"q-option\" onclick=\"selectOption(2,0,0)\"><span class=\"opt-icon\">✅</span>Buri nshuro yose</button>\n        <button class=\"q-option\" onclick=\"selectOption(2,1,1)\"><span class=\"opt-icon\">📊</span>Inshuro nyinshi</button>\n        <button class=\"q-option\" onclick=\"selectOption(2,2,2)\"><span class=\"opt-icon\">⚠️</span>Rimwe na rimwe / gake</button>\n        <button class=\"q-option\" onclick=\"selectOption(2,3,2)\"><span class=\"opt-icon\">🚫</span>Ntago nabigeze / ntago nkora imibonano</button>",
  "str_1946": "Ikibazo cya 3 kuri 5",
  "str_1947": "Wigeze ubona ikibazo cyo gusaba uwo mubanariye gukoresha agakingirizo?",
  "str_1948": "Imbaraga z'imyanya ni inzitizi nkuru ku bagore bato mu Rwanda (DHS 2025).",
  "str_1949": "<button class=\"q-option\" onclick=\"selectOption(3,0,0)\"><span class=\"opt-icon\">✅</span>Oya — numva mfite icyizere cyo kuvugana</button>\n        <button class=\"q-option\" onclick=\"selectOption(3,1,1)\"><span class=\"opt-icon\">😐</span>Rimwe na rimwe biragorana</button>\n        <button class=\"q-option\" onclick=\"selectOption(3,2,2)\"><span class=\"opt-icon\">⚠️</span>Yego, kenshi birangora</button>\n        <button class=\"q-option\" onclick=\"selectOption(3,3,0)\"><span class=\"opt-icon\">➖</span>Ntabwo binziraho</button>",
  "str_1950": "Ikibazo cya 4 kuri 5",
  "str_1951": "Ubuzuye ubumenyi bwawe ku Virusi itera SIDA bute?",
  "str_1952": "Abahungu ba 52.7% gusa b'imyaka 15–24 bafite ubumenyi buzuye bwa Virusi itera SIDA (Rwanda DHS 2025, Imbonerahamwe 15).",
  "str_1953": "<button class=\"q-option\" onclick=\"selectOption(4,0,0)\"><span class=\"opt-icon\">📚</span>Nzi uko virusi ikwirakwira, uko bwirinda, n'ukuri kose</button>\n        <button class=\"q-option\" onclick=\"selectOption(4,1,1)\"><span class=\"opt-icon\">📖</span>Nzi iby'ibanze ariko hari ibyo ntazi</button>\n        <button class=\"q-option\" onclick=\"selectOption(4,2,2)\"><span class=\"opt-icon\">❓</span>Nta cyizere nzi neza ku kuri kwa virusi</button>\n        <button class=\"q-option\" onclick=\"selectOption(4,3,3)\"><span class=\"opt-icon\">🚨</span>Mfite ubumenyi buke cyane</button>",
  "str_1954": "Ikibazo cya 5 kuri 5",
  "str_1955": "Ufite ubushobozi bwo kwipimisha Virusi itera SIDA mu karere kawe?",
  "str_1956": "Ubushobozi buke buragaragarira cyane mu baturage bo mu cyaro n'abaherereye mu bwige.",
  "str_1957": "<button class=\"q-option\" onclick=\"selectOption(5,0,0)\"><span class=\"opt-icon\">✅</span>Yego — ivuriro riri hafi kandi ryoroshye kugeraho</button>\n        <button class=\"q-option\" onclick=\"selectOption(5,1,1)\"><span class=\"opt-icon\">🛣️</span>Yego, ariko riri kure cyangwa bisaba amafaranga menshi</button>\n        <button class=\"q-option\" onclick=\"selectOption(5,2,2)\"><span class=\"opt-icon\">⚠️</span>Oya — akato cyangwa intera ni inzitizi</button>\n        <button class=\"q-option\" onclick=\"selectOption(5,3,2)\"><span class=\"opt-icon\">🚨</span>Nta buryo bwo kwipima buri mu muryango wanjye</button>",
  "str_1958": "<button class=\"q-nav-btn\" id=\"btn-back\" onclick=\"goBack()\" style=\"display:none\">← Inyuma</button>\n    <button class=\"q-nav-btn next\" id=\"btn-next\" onclick=\"goNext()\" disabled=\"\">Komeza →</button>",
