  "str_2280": "Inyandiko ya iAccelerator Igice cya 7 &nbsp;|&nbsp; Rwanda, 2025 &nbsp;|&nbsp; Yubatswe ku Ngaruka",
  "str_2281": "<button onclick=\"shareRinda()\" style=\"display:inline-flex;align-items:center;gap:.5rem;padding:.65rem 1.4rem;border-radius:40px;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.15);color:rgba(255,255,255,0.8);font-size:.85rem;font-weight:600;cursor:pointer;transition:.3s;font-family:'Inter',sans-serif\" onmouseover=\"this.style.background='rgba(0,160,220,0.2)'\" onmouseout=\"this.style.background='rgba(255,255,255,0.08)'\">📤 Share this Platform</button>\n    <a href=\"pitch.html\" style=\"display:inline-flex;align-items:center;gap:.5rem;padding:.65rem 1.4rem;border-radius:40px;background:rgba(250,210,1,0.12);border:1px solid rgba(250,210,1,0.35);color:#FAD201;font-size:.85rem;font-weight:600\">📊 View Pitch Deck</a>\n    <a href=\"app/index.html\" style=\"display:inline-flex;align-items:center;gap:.5rem;padding:.65rem 1.4rem;border-radius:40px;background:rgba(0,160,220,0.15);border:1px solid rgba(0,160,220,0.35);color:#00A0DC;font-size:.85rem;font-weight:600\">🚀 Enter Platform</a>",
