  "str_2285": "<a href=\"#problem\">Ikibazo</a>\n    <a href=\"#solution\">Igisubizo</a>\n    <a href=\"#impact\">Ingaruka</a>\n    <a href=\"#ask\">Ibisabwa</a>",
  "str_2286": "Gerageza Urubuga →",
  "str_2287": "iAccelerator 7 · Rwanda · 2025",
  "str_2288": "Inzira ya <span>Rinda</span><br>Initiative",
  "str_2289": "Urubuga rw'ikoranabuhanga rwuzuye bilingual, ruhuza abafite ubumuga, rwo gukumira Virusi itera SIDA rugeraho urubyiruko 15M+ rw'u Rwanda rugwa mu cyuho cy'ubuvuzi — binyurando mu smartphone, USSD, n'inzego.",
  "str_2290": "Youth aged 15–24 who have never tested for HIV<br><span style=\"color:var(--dim);font-size:.65rem\">Rwanda 2025 DHS</span>",
  "str_2291": "Women with no education who have HIV knowledge<br><span style=\"color:var(--dim);font-size:.65rem\">Rwanda 2025 DHS</span>",
  "str_2292": "15M+",
  "str_2293": "Rwandans without smartphones — reachable via USSD<br><span style=\"color:var(--dim);font-size:.65rem\">RURA 2024</span>",
  "str_2294": "🚨 Ikibazo",
  "str_2295": "Gahunda yo Gukumira Virusi itera SIDA y'u Rwanda ifite ibyuya bine bikomeye",
  "str_2296": "Byose bine byanditswe mu Musozoro w'Ubuzima n'Imibereho ya Rwanda 2025",
  "str_2297": "of youth 15–24 have <strong>never been tested</strong> — they don't know their status",
  "str_2298": "📊 Rwanda 2025 DHS, Table 12.7",
  "str_2299": "of women with no education have HIV knowledge — <strong>2× lower</strong> than educated peers",
  "str_2300": "📊 Rwanda 2025 DHS, Chapter 12",
  "str_2301": "15M+",
  "str_2302": "Rwandans own <strong>basic phones only</strong> — locked out of smartphone health apps",
  "str_2303": "📊 RURA Mobile Penetration Report 2024",
  "str_2304": "of PWD youth have ever accessed HIV services — <strong>disability exclusion is systemic</strong>",
  "str_2305": "📊 Rwanda 2025 DHS, Table 14.2",
  "str_2306": "✅ Igisubizo Cyacu",
  "str_2307": "Rinda: Urubuga rumwe, inzitizi zose zivanywemo",
  "str_2308": "Ibikoresho bitandatu birimo imbere birindana kugira ngo bigereke ku rubyiruko ruhambaye guhambira",
  "str_2309": "Gutumiza Igikoresho mu Ibanga",
  "str_2310": "Nta zina, nta ndangamuntu. Ibikoresho byo kwipima bizanwa mu bipfunyika bisanzwe n'inzego zafunzwe mu masaa 48.",
  "str_2311": "USSD (*775#)",
  "str_2312": "Nta smartphone, nta amadata bisabwa. Umukoresha wa telefone nsanganzaburi wese abona serivisi zose mu Kinyarwanda.",
  "str_2313": "Inyigisho z'Inkuru",
  "str_2314": "Inkuru nyakuri zo gukumira Virusi itera SIDA zerekeye urubyiruko rw'u Rwanda — zubaka ubumenyi nta soni cyangwa inyigisho nk'iz'ishuri.",
  "str_2315": "Ubumenyi",
  "str_2316": "Ikarita 20 zemejwe muganga mu nkingi 6. Gusomwa n'ijwi ku bakoresha badafite ubushobozi bwo gusoma &amp; abafite ibibazo by'amaso.",
  "str_2317": "Ikizamini cyo Gupima Ibyago",
  "str_2318": "Amanota y'ibyago bya Virusi itera SIDA bihariye hamwe n'inzira z'ingaruka za mwakurikijwe neza ku muco — nta guca imanza.",
  "str_2319": "Ubwubatsi Buhuza Abafite Ubumuga",
  "str_2320": "Uburyo bwa kontrasti, ingano y'ibyandikwa, ubufasha bwa screen reader, option y'inzego z'ururimi rw'amarenga — kuva ku munsi wa mbere.",
  "str_2321": "⚙️ Uko Bikora",
  "str_2322": "Guhera ku gutigira kugeza ku bisubizo by'ikizamini mu masaa 48",
  "str_2323": "Urubyiruko rubona Rinda — mu buryo ubwo ari bwo bwose",
  "str_2324": "Binyurando mu rubuga mushya kuri smartphone, CYANGWA ukanda *775# ku telefone iyo ari yo yose nsanganzaburi, CYANGWA uvuye ku nzego muri ishuri, ivuriro, cyangwa guterana kw'umuryango. Nta interineti bisabwa kuri USSD.",
  "str_2325": "Gufata Ikizamini cyo Gupima Ibyago vuba (iminota 3)",
  "str_2326": "Ibibazo 10 by'ibanga bisohora amanota y'ibyago bya Virusi itera SIDA bihariye. Bakeya/Bigerwa/Bikabije hamwe n'inzira z'ingaruka za vuba, nta guca imanza. Imibare yose ibikwa ku gikoresho — nta kintu kibikwa muri seriveri.",
  "str_2327": "Asaba igikoresho cyo kwipima mu ibanga",
  "str_2328": "Nta zina, nta ndangamuntu, nta jya ku ivuriro bisabwa. Ahitamo akarere ke. Inzego zafunzwe zipakira igikoresho mu bipfunyika bisanzwe kandi zizane mu masaa 24–48 — idirişa hifashishijwe.",
  "str_2329": "Ahabwa ibisubizo + yiga ibyo gukora hakurikijwe",
  "str_2330": "Ubumenyi busobanura neza uko gusoma ibisubizo. Niba bifite, app ihubuka kumurongo w'ubujyanama w'ubuntu 114. Niba bitafite, ishyira reminder yo kwipima buri mezi 6 automatique.",
  "str_2331": "📊 Intego z'Ingaruka z'Umwaka wa 1",
  "str_2332": "Intego zishingiye ku mibare, zijyanye n'ibyuya bya DHS",
  "str_2333": "Urubyiruko rw'imyaka 15–24 rwigeze kwipimishwa Virusi itera SIDA bwa mbere",
  "str_2334": "Abakoresha barangije ibibazo byose by'inyigisho (ubumenyi bubikiwe)",
  "str_2335": "Abakoresha ba USSD bagezeho nta smartphone",
  "str_2336": "Abafite ubumuga bakorerwa — urubuga rwa mbere rwuhuza abafite ubumuga rwo gukumira Virusi itera SIDA mu Rwanda",
  "str_2337": "Inzego zafunzwe muri Kigali, Amajyepfo &amp; Uburasirazuba",
  "str_2338": "Guhura n'isoni — ubwubatsi bw'ibanga bwa mbere buvanaho inzitizi zo kugaragaza",
  "str_2339": "💼 Modeli y'Ubucuruzi",
  "str_2340": "Inzira z'umusaruro zihuje n'ingufu y'ubuzima bw'u Rwanda",
  "str_2341": "💰 Inzira z'Umusaruro",
